#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10,mod=1e9+7;

int T,n,sum[N],c[N],inv[N],b[N],mi[N],ivm[N];
long long k;
char s[N];

void init(){
    inv[0]=inv[1]=1;
    for(int i=2;i<N;i++)
        inv[i]=1ll*(mod-mod/i)*inv[mod%i]%mod;
    mi[0]=ivm[0]=1;
    for(int i=1;i<N;i++){
        mi[i]=2*mi[i-1]%mod;
        ivm[i]=1ll*inv[2]*ivm[i-1]%mod;
    }
}

int main(){
    init();
    scanf("%d",&T);
    while(T--){
        scanf("%d%lld",&n,&k);
        scanf("%s",s+1);
        if(!k){
            if(s[1]!='0' || s[n]!='1'){
                puts("0");
                continue;
            }
            int cnt=0;
            for(int i=2;i<=n;i++)
                if(s[i]=='0' && s[i-1]=='1')
                    cnt++;
            printf("%d\n",mi[cnt]);
            continue;
        }
        b[0]=1;
        k%=mod;
        for(int i=1;i<=n;i++)
            b[i]=1ll*b[i-1]*(i+k-1)%mod*inv[i]%mod;
        int ans=0,cnt;
        for(int r=1;r<=n;r++){
            c[r]=c[r-1]+(r>1 && s[r]=='0' && s[r-1]=='1');
            sum[r]=sum[r-1];
            if(s[r]=='0')
                sum[r]=(sum[r-1]+1ll*b[r-1]*ivm[c[r]])%mod;
            else
                ans=(ans+1ll*mi[c[r]]*b[n-r]%mod*sum[r])%mod;
        }
        printf("%d\n",ans);
    }
    return 0;
}
